classDiagram(name = "ParkingGarage") {
    val parkingGarage = classOf(name = "ParkingGarage")
    val level = classOf(name = "Level")
    val parkingSpace = classOf(name = "ParkingSpace") {
        isAbstract = true
    }
    val regularSpace = classOf(name = "RegularSpace") {
        extends(general = parkingSpace)
    }
    val disabledSpace = classOf(name = "DisabledSpace") {
        extends(general = parkingSpace)
    }
    val electricChargingSpace = classOf(name = "ElectricChargingSpace") {
        extends(general = parkingSpace)
    }
    val ticket = classOf(name = "Ticket") {
        attribute(name = "entryTime", type = "DateTime")
    }

    association(source = parkingGarage, target = level) {
        aggregation = AggregationKind.COMPOSITE
        source { multiplicity(spec = "1") }
        target { multiplicity(spec = "1..*"); role = "levels" }
    }

    association(source = level, target = parkingSpace) {
        aggregation = AggregationKind.COMPOSITE
        source { multiplicity(spec = "1") }
        target { multiplicity(spec = "1..*"); role = "spaces" }
    }

    association(source = ticket, target = parkingSpace) {
        source { multiplicity(spec = "0..1"); role = "assignedTo" }
        target { multiplicity(spec = "0..1"); role = "occupiedBy" }
    }
}

