@startuml

abstract class Payment {
  amount: float
  date: Date
}
class MembershipFee {
  contributionYear: int
}
class Donation
class Member {
  status: MemberStatus
}
interface Notifiable
class MembershipApplication {
  status: ApplicationStatus
}
class StateChapter
class DistrictChapter
class Committee
class Mandate {
  termOfOffice: String
}
class Campaign
class Deployment {
  numberOfHours: int
}

enum MemberStatus {
  active
  passive
  resigned
}
enum ApplicationStatus {
  received
  reviewed
  accepted
  rejected
}

' Structure
StateChapter "1" *-- "1..*" DistrictChapter
DistrictChapter "1" *-- "0..*" Member

' Inheritance & Realization
Payment <|-- MembershipFee
Payment <|-- Donation
Notifiable <|.. Member

' Associations
Member "1" -- "0..*" Payment : originates from
Donation "*" -- "0..1" Campaign : earmarked for

DistrictChapter "1" -- "0..*" MembershipApplication : handles
MembershipApplication "1" -- "0..1" Member : creates

Committee "1" -- "0..*" Mandate : awards
Mandate "*" -- "1" Member : held by

DistrictChapter "1" -- "0..*" Campaign : runs
(Campaign, Member) .. Deployment

@enduml

